import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthManager {
  static final AuthManager _instance = AuthManager._internal();
  factory AuthManager() => _instance;

  AuthManager._internal();

  Future<void> saveLogin(String token, String userData) async {
    SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setString('authToken', token);
    await prefs.setString('userData', userData);
  }

  Future<Map<String, dynamic>> getLoginData() async {
    SharedPreferences prefs = await SharedPreferences.getInstance();
    String? token = prefs.getString('authToken');
    String? userData = prefs.getString('userData');
    return {'token': token, 'userData': userData};
  }

  Future<void> logout() async {
    SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.remove('authToken');
    await prefs.remove('userData');
  }
}

class AuthProvider extends ChangeNotifier {
  String? _authToken;
  String? _userData;

  String? get authToken => _authToken;
  String? get userData => _userData;

  Future<void> login(String token, String userData) async {
    _authToken = token;
    _userData = userData;
    await AuthManager().saveLogin(token, userData);
    notifyListeners();
  }

  Future<void> checkLogin() async {
    Map<String, dynamic> data = await AuthManager().getLoginData();
    if (data['token'] != null && data['userData'] != null) {
      _authToken = data['token'];
      _userData = data['userData'];
      notifyListeners();
    }
  }

  Future<void> logout() async {
    _authToken = null;
    _userData = null;
    await AuthManager().logout();
